<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">X-Content-Type-Options</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nosniff</span></span>
